import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

function Login() {
  const [formData, setFormData] = useState({ email: '', password: '' });
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    
    // Direct Action: No password check, just redirect
    console.log("Login Data:", formData);
    
    // Save to localStorage so dashboard knows someone is logged in
    localStorage.setItem("isLoggedIn", "true");
    localStorage.setItem("userEmail", formData.email);

    // Redirect to Dashboard
    navigate('/client-dashboard');
  };

  return (
    <div className="login-container d-flex justify-content-center align-items-center vh-100 bg-light">
      <div className="card p-4 shadow" style={{ width: '350px' }}>
        <h2 className="text-center mb-4">Login</h2>
        <form onSubmit={handleSubmit}>
          <div className="mb-3">
            <input 
              type="email" name="email" className="form-control" 
              placeholder="Email" onChange={handleChange} required 
            />
          </div>
          <div className="mb-3">
            <input 
              type="password" name="password" className="form-control" 
              placeholder="Password" onChange={handleChange} required 
            />
          </div>
          <button type="submit" className="btn btn-primary w-100">Login Now</button>
        </form>
      </div>
    </div>
  );
}

export default Login;
